tlDataChunk*
tlAnimationGroupChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Pure3D::Animation::ChannelData::INT:
        dch = new tlIntChannelChunk(&ch);
        break;
    case Pure3D::Animation::ChannelData::FLOAT_1:
        dch = new tlFloat1ChannelChunk(&ch);
        break;
    case Pure3D::Animation::ChannelData::FLOAT_2:
        dch = new tlFloat2ChannelChunk(&ch);
        break;
    case Pure3D::Animation::ChannelData::VECTOR_1DOF:
        dch = new tlVector1DOFChannelChunk(&ch);
        break;
    case Pure3D::Animation::ChannelData::VECTOR_2DOF:
        dch = new tlVector2DOFChannelChunk(&ch);
        break;
    case Pure3D::Animation::ChannelData::VECTOR_3DOF:
        dch = new tlVector3DOFChannelChunk(&ch);
        break;
    case Pure3D::Animation::ChannelData::QUATERNION:
        dch = new tlQuaternionChannelChunk(&ch);
        break;
    case Pure3D::Animation::ChannelData::COMPRESSED_QUATERNION:
        dch = new tlCompressedQuaternionChannelChunk(&ch);
        break;
    case Pure3D::Animation::ChannelData::STRING:
        dch = new tlStringChannelChunk(&ch);
        break;
    case Pure3D::Animation::ChannelData::ENTITY:
        dch = new tlEntityChannelChunk(&ch);
        break;
    case Pure3D::Animation::ChannelData::BOOL:
        dch = new tlBoolChannelChunk(&ch);
        break;
    case Pure3D::Animation::ChannelData::COLOUR:
        dch = new tlColourChannelChunk(&ch);
        break;
    case Pure3D::Animation::ChannelData::EVENT:
        dch = new tlEventChannelChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

